UPDATE hotel_kiosk.stocks
SET stock_count = (stock_count + 1)
WHERE stock_id = #{stockId}

UPDATE hotel_kiosk.stocks
SET stock_count = (stock_count - 1)
WHERE stock_id = #{stockId}

UPDATE hotel_kiosk.stocks
SET stock_count = #{stockCount}, min_stock = #{minStock}
WHERE stock_id = #{stockId}
